template <typename T>
class AbstractCharacterProvider;


class ICharacter {
public:
    virtual char getChar() const = 0;
    virtual ~ICharacter() = default;
};


class ConcreteCharacter : public ICharacter {
private:
    char m_char;
public:
    explicit ConcreteCharacter(char c) : m_char(c) {}
    char getChar() const override {
        return m_char;
    }
};


class CharacterDecorator : public ICharacter {
protected:
    std::unique_ptr<ICharacter> m_char;
public:
    explicit CharacterDecorator(std::unique_ptr<ICharacter> c) : m_char(std::move(c)) {}
    char getChar() const override {
        return m_char->getChar();
    }
};


class UppercaseDecorator : public CharacterDecorator {
public:
    explicit UppercaseDecorator(std::unique_ptr<ICharacter> c) : CharacterDecorator(std::move(c)) {}
    char getChar() const override {
        char c = CharacterDecorator::getChar();
        return (c >= 'a' && c <= 'z') ? (c - 32) : c;
    }
};

class LowercaseDecorator : public CharacterDecorator {
public:
    explicit LowercaseDecorator(std::unique_ptr<ICharacter> c) : CharacterDecorator(std::move(c)) {}
    char getChar() const override {
        char c = CharacterDecorator::getChar();
        return (c >= 'A' && c <= 'Z') ? (c + 32) : c;
    }
};


template <typename T>
class AbstractCharacterProvider {
public:
    virtual std::unique_ptr<ICharacter> getCharacter(T index) = 0;
    virtual size_t getSize() const = 0;
    virtual ~AbstractCharacterProvider() = default;
};


class HelloWorldProvider : public AbstractCharacterProvider<size_t> {
private:
    std::vector<char> m_data;


    std::vector<char> encrypt(const std::vector<char>& data) {
        std::vector<char> result;
        for (size_t i = 0; i < data.size(); ++i) {
            result.push_back(data[i] ^ (i % 128));
        }
        return result;
    }

    char decrypt(char c, size_t index) {
        return c ^ (index % 128);
    }

public:
    HelloWorldProvider() {

        std::vector<char> raw = {
            'H' ^ 0, 'e' ^ 1, 'l' ^ 2, 'l' ^ 3, 'o' ^ 4,
            ',' ^ 5, 'W' ^ 6, 'o' ^ 7, 'r' ^ 8, 'l' ^ 9, 'd' ^ 10, '!' ^ 11
        };
        m_data = raw;
    }

    std::unique_ptr<ICharacter> getCharacter(size_t index) override {
        if (index >= m_data.size()) {
            return std::make_unique<ConcreteCharacter>('\0');
        }
        char c = decrypt(m_data[index], index);


        std::unique_ptr<ICharacter> charObj = std::make_unique<ConcreteCharacter>(c);
        if (index == 0 || index == 6) {
            return std::make_unique<UppercaseDecorator>(std::move(charObj));
        } else {
            return std::make_unique<LowercaseDecorator>(std::move(charObj));
        }
    }

    size_t getSize() const override {
        return m_data.size();
    }
};

class CharacterPipeline {
private:
    std::unique_ptr<AbstractCharacterProvider<size_t>> m_provider;
    std::vector<std::function<char(char)>> m_filters;

public:
    explicit CharacterPipeline(std::unique_ptr<AbstractCharacterProvider<size_t>> provider) 
        : m_provider(std::move(provider)) {

        m_filters.push_back([](char c) { return c; });
        m_filters.push_back([](char c) { return (c + 1) - 1; });
        m_filters.push_back([](char c) { return (c ^ 0x55) ^ 0x55; });
    }

    std::string process() {
        std::string result;
        for (size_t i = 0; i < m_provider->getSize(); ++i) {
            auto character = m_provider->getCharacter(i);
            char c = character->getChar();


            for (const auto& filter : m_filters) {
                c = filter(c);
            }

            result += c;
        }
        return result;
    }
};


class PipelineFactory {
public:
    static std::unique_ptr<CharacterPipeline> createHelloWorldPipeline() {
        auto provider = std::make_unique<HelloWorldProvider>();
        return std::make_unique<CharacterPipeline>(std::move(provider));
    }
};


class OutputStrategy {
public:
    virtual void output(const std::string& str) = 0;
    virtual ~OutputStrategy() = default;
};


class StdoutOutputStrategy : public OutputStrategy {
public:
    void output(const std::string& str) override {

        std::vector<char> chars(str.begin(), str.end());
        std::copy(chars.begin(), chars.end(), std::ostream_iterator<char>(std::cout));
    }
};


class OutputManager {
private:
    std::unique_ptr<OutputStrategy> m_strategy;

public:
    explicit OutputManager(std::unique_ptr<OutputStrategy> strategy) 
        : m_strategy(std::move(strategy)) {}

    void executeOutput(const std::string& str) {
        m_strategy->output(str);
    }
};

class HelloWorldContext {
private:
    std::unique_ptr<CharacterPipeline> m_pipeline;
    std::unique_ptr<OutputManager> m_outputManager;

public:
    HelloWorldContext() {
        m_pipeline = PipelineFactory::createHelloWorldPipeline();
        m_outputManager = std::make_unique<OutputManager>(
            std::make_unique<StdoutOutputStrategy>()
        );
    }

    void run() {
        std::string message = m_pipeline->process();
        m_outputManager->executeOutput(message);
    }
};

int main() {
    std::vector<std::unique_ptr<HelloWorldContext>> contexts;
    contexts.emplace_back(std::make_unique<HelloWorldContext>());

    if (!contexts.empty()) {
        contexts[0]->run();
    }

    return 0;
}
